pub fn isCombiningMark(cp: u32) bool {
    var lo: usize = 0;
    var hi: usize = combining_mark_ranges.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        const r = combining_mark_ranges[mid];
        if (cp < r.start) {
            hi = mid;
        } else if (cp > r.end) {
            lo = mid + 1;
        } else {
            return true;
        }
    }
    return false;
}
